// R-02: fail-closed — Linear uses HMAC-SHA256, not a simple token
const crypto = require('crypto');
const secret = $env['LINEAR_WEBHOOK_SECRET'] ?? '';
const sig = $input.first().headers['linear-signature'] ?? '';
if (!secret || !sig) throw new Error('Missing Linear webhook signature — dropping (R-02)');

const body = JSON.stringify($input.first().json);
const expected = crypto.createHmac('sha256', secret).update(body).digest('hex');
if (sig !== expected) throw new Error('Invalid Linear webhook signature — dropping (R-02)');

const payload = $input.first().json;
const action = payload.action;
const issueData = payload.data ?? {};

return [{
  json: {
    action,
    issue_id: issueData.id,
    issue_identifier: issueData.identifier,
    title: issueData.title,
    state: issueData.state?.name,
    assignee: issueData.assignee?.name,
    url: issueData.url,
    team: issueData.team?.name,
    timestamp: new Date().toISOString()
  }
}];
